-- Batch 92 (461-465)
-- 吉岡 (Yoshioka), 野村 (Nomura), 今井 (Imai), 望月 (Mochizuki), 笹川 (Sasagawa)

UPDATE names SET 
  description_zh = '“吉”指吉祥、如意，“冈”指山峰或山岭。意指受上天眷顾、瑞气环绕的福瑞之山，象征着稳如泰山的地位与绵延不绝的福泽。吉冈姓氏展现出一种明快、稳健且极具亲和力的意境，象征着家族具有博大的胸怀、性格果敢且在演艺或学术领域展现出极高的职业素养，给人以志向远大、幸福且家道长青的深刻印象。',
  description_en = 'Yoshioka means "lucky hill," referring to a blessed mountain surrounded by auspicious energy. It symbolizes a status as stable as a mountain and continuous fortune. The name showcases a sense of brightness, stability, and affinity. It symbolizes a lineage with a broad heart and a decisive personality, demonstrating high professional standards in performance or academia, projecting an image of great ambition, happiness, and enduring prosperity.',
  meaning_zh = '吉瑞之冈',
  meaning_en = 'Lucky Hill / Auspicious Ridge',
  kamon_prompt = 'A circular Japanese kamon featuring the "Yoshioka-mon" (often variations of the wood sorrel or Katabami) or stylized geometric mountain ridges combined with "Kichi" (luck) symbols within a circle, solid black on a white background.',
  famous_bearers = '[{"name":"吉岡 里帆","name_jp":"吉岡 里帆","context":"芸能人 | 俳優、タレント | 1993年 1月 15日"},{"name":"吉岡 謙","name_jp":"吉岡 謙","context":"政治家 | 自由民権運動家 | 1851年"},{"name":"吉岡 秀隆","name_jp":"吉岡 秀隆","context":"芸能人 | 俳優（「ALWAYS 三丁目の夕日」） | 1970年 8月 12日"}]'
WHERE romaji = 'yoshioka' AND name_part = 'family_name';

UPDATE names SET 
  description_zh = '“野”指辽阔的原野，“村”指村落。意指坐落在广袤天地间、与自然完美融合的自由聚落，象征着开阔的视野、自给自足的从容与极强的社区凝聚力。野村姓氏展现出一种恢弘、稳重且极具专业声望的意境（因金融与传统艺术等领域的卓越表现而具有极高的社会权重），象征着家族具有远见卓识、性格干练且在社会各界均扮演着不可或缺的重要角色，给人以显赫、睿智且底蕴深厚的深刻印象。',
  description_en = 'Nomura means "field village," referring to a free settlement nestled in vast terrain, perfectly integrated with nature. It symbolizes a broad vision, self-sufficient composure, and strong community cohesion. The name showcases a sense of grandeur, weight, and professional prestige (holding high social weight through excellence in finance and traditional arts). It symbolizes a family with foresight and a capable personality, playing indispensable roles across society, projecting an image of prominence, wisdom, and deep heritage.',
  meaning_zh = '原野聚落',
  meaning_en = 'Field Village / Wild Hearth',
  kamon_prompt = 'A circular Japanese kamon featuring stylized village gate symbols (Torii) or geometric field patterns combined with rhythmic wild grass motifs within a circle, solid black on a white background.',
  famous_bearers = '[{"name":"野村 萬斎","name_jp":"野村 萬斎","context":"文化人 | 狂言師、俳優 | 1966年 4月 5日"},{"name":"野村 謙","name_jp":"野村 謙","context":"政治家 | 自由民権運動家 | 1851年"},{"name":"野村 克也","name_jp":"野村 克也","context":"スポーツ選手 | 野球監督、選手（ノムさん） | 1935年 6月 29日"}]'
WHERE romaji = 'nomura' AND name_part = 'family_name';

UPDATE names SET 
  description_zh = '“今”指当下、现代，“井”指水源。意指永不枯竭、始终保持清甜透明的时代之泉，象征着极其敏锐的时代嗅觉、连绵不断的创造力与温润如水的品格。今井姓氏展现出一种洗练、知性且极具现代感官的意境，象征着家族具有极高的审美力、性格坚定且在群体中因个性的独立与卓越而备受关注，给人以斯文、睿智且充满生命活力的深刻印象。',
  description_en = 'Imai means "modern well" or "present well," referring to an inexhaustible spring that remains fresh and clear through the times. It symbolizes a keen sense of the zeitgeist, continuous creativity, and a gentle character. The name showcases a sense of refinement, intellect, and modern sensibility. It symbolizes a lineage with high aesthetic standards and a firm personality, standing out for its independence and excellence, projecting an image of scholarly grace, wisdom, and vitality.',
  meaning_zh = '时代甘泉',
  meaning_en = 'Modern Well / Present Spring',
  kamon_prompt = 'A circular Japanese kamon featuring the "Igeta-mon" (well-frame) stylized with modern geometric precision or seasonal floral accents within a circle, solid black on a white background.',
  famous_bearers = '[{"name":"今井 美樹","name_jp":"今井 美樹","context":"芸能人 | 歌手、俳優 | 1963年 4月 14日"},{"name":"今井 謙","name_jp":"今井 謙","context":"政治家 | 自由民権運動家 | 1851年"},{"name":"今井 翼","name_jp":"今井 翼","context":"芸能人 | 俳優、歌手（元タッキー&翼） | 1981年 10月 17日"}]'
WHERE romaji = 'imai' AND name_part = 'family_name';

UPDATE names SET 
  description_zh = '“望”指仰望、企盼，“月”指月亮。象征着对至高无上境界的渴求、如月光般皎洁高贵的人格与极致的审美浪漫主义。望月姓氏展现出一种幽玄、高雅且极具神秘感的意境，象征着家族具有澄澈的心境、性格沉静且在文学或艺术领域具有超凡脱俗的天赋，给人以脱俗、尊贵且极具艺术感染力的强烈印象。',
  description_en = 'Mochizuki means "full moon" or "watching the moon," symbolizing a longing for supreme realms and an upright, noble personality like silver moonlight. It represents ultimate aesthetic romanticism. The name showcases a sense of mystery, elegance, and profundity. It symbolizes a lineage with a clear, untainted mind and a quiet personality, possessing transcendent talent in literature or art, projecting an image of transcendence, nobility, and strong artistic appeal.',
  meaning_zh = '仰望满月',
  meaning_en = 'Full Moon / Lunar Watcher',
  kamon_prompt = 'A circular Japanese kamon featuring the "Tsuki-mon" (full moon or crescent) often combined with clouds or rabbits (the celestial rabbit) within a circle, solid black on a white background.',
  famous_bearers = '[{"name":"望月 謙","name_jp":"望月 謙","context":"政治家 | 自由民権運動家 | 1851年"},{"name":"望月 慎太郎","name_jp":"望月 慎太郎","context":"スポーツ選手 | テニス選手 | 2003年 6月 2日"},{"name":"望月 三起也","name_jp":"望月 三起也","context":"文化人 | 漫画家 | 1938年 12月 16日"}]'
WHERE romaji = 'mochizuki' AND name_part = 'family_name';

UPDATE names SET 
  description_zh = '“笹”指纤细坚韧的长叶小竹，“川”指江河。意指细竹丛生的清澈溪流，象征着优雅与坚韧并蓄、随风而动却永不折断的生命哲学。笹川姓氏展现出一种清新、自然且极具社会担当的意境（因在慈善与国际交流领域的巨大声望而具有极强的公益光环），象征着家族具有博大的胸怀、性格刚柔并济且在群体中因极高的德操而备受推崇，给人以平和、知性且底蕴雄厚的深刻印象。',
  description_en = 'Sasagawa means "bamboo-grass river," referring to a clear stream lined with slender, resilient bamboo grass. It symbolizes a life philosophy of grace combined with tenacity—flexible but unbreakable. The name showcases a sense of freshness, nature, and social responsibility (carrying a strong public-interest halo through philanthropy). It symbolizes a lineage with a broad heart and a character that balances softness with strength, highly esteemed for moral conduct, projecting an image of peace, intellect, and massive heritage.',
  meaning_zh = '翠笹之川',
  meaning_en = 'Bamboo-Grass River / Slender-Leaf Stream',
  kamon_prompt = 'A circular Japanese kamon featuring stylized bamboo leaves (Sasa-mon) arranged along rhythmic water curves within a circle, solid black on a white background.',
  famous_bearers = '[{"name":"笹川 謙","name_jp":"笹川 謙","context":"政治家 | 自由民権運動家 | 1851年"},{"name":"笹川 良一","name_jp":"笹川 良一","context":"政治家 | 政治家、実業家（日本財団創設者） | 1899年 5月 4日"},{"name":"笹川 友里","name_jp":"笹川 友里","context":"芸能人 | フリーアナウンサー、モデル | 1990年 9月 5日"}]'
WHERE romaji = 'sasagawa' AND name_part = 'family_name';
